def split_bill(total, tip_percent, people):
    total_with_tip = total + total * tip_percent / 100
    return total_with_tip / people

def convert_minutes(total_minutes):
    return {
        "hours": total_minutes // 60,
        "minutes": total_minutes % 60
    }

def even_or_odd(number):
    if number % 2 == 0:
        return "even"
    return "odd"

def grade_letter(score):
    if score >= 90:
        return "A"
    if score >= 80:
        return "B"
    if score >= 70:
        return "C"
    if score >= 60:
        return "D"
    return "F"

def shipping_cost(weight):
    if weight <= 1:
        return 5
    if weight <= 5:
        return 8
    if weight <= 20:
        return 15
    return 25

def is_leap_year(year):
    if year % 400 == 0:
        return True
    if year % 100 == 0:
        return False
    return year % 4 == 0

def login_status(username, password):
    if username == "admin" and password == "secret":
        return "admin"
    if username == "student" and password == "learn":
        return "user"
    return "denied"

def sum_to_n(n):
    total = 0
    for value in range(1, n + 1):
        total += value
    return total

def countdown(n):
    result = []
    for value in range(n, 0, -1):
        result.append(value)
    return result

def multiplication_row(number, length):
    result = []
    for value in range(1, length + 1):
        result.append(number * value)
    return result

def factorial_loop(n):
    result = 1
    for value in range(2, n + 1):
        result *= value
    return result

def first_above(numbers, limit):
    for number in numbers:
        if number > limit:
            return number
    return None

def greet(name, excited=False):
    if excited:
        return "Hello, " + name + "!"
    return "Hello, " + name + "."

def apply_discount(price, discount_percent):
    if discount_percent < 0:
        discount_percent = 0
    elif discount_percent > 100:
        discount_percent = 100
    return price * (1 - discount_percent / 100)

def format_full_name(first, last, middle=''):
    if middle:
        return f"{first} {middle} {last}"
    return f"{first} {last}"

def score_summary(scores):
    if not scores:
        return None
    return {
        "min": min(scores),
        "max": max(scores),
        "average": sum(scores) / len(scores)
    }

def count_vowels(text):
    count = 0
    for char in text.lower():
        if char in "aeiou":
            count += 1
    return count

def is_palindrome(text):
    cleaned = text.replace(" ", "").lower()
    return cleaned == cleaned[::-1]

def initials(full_name):
    result = ""
    for word in full_name.split():
        result += word[0].upper()
    return result

def mask_email(email):
    username, domain = email.split("@", 1)
    if len(username) <= 2:
        return email
    return username[0] + "***" + username[-1] + "@" + domain

def positives(numbers):
    result = []
    for number in numbers:
        if number > 0:
            result.append(number)
    return result

def square_all(numbers):
    result = []
    for number in numbers:
        result.append(number * number)
    return result

def average_without_lowest(scores):
    if len(scores) < 2:
        return None
    remaining = scores.copy()
    remaining.remove(min(remaining))
    return sum(remaining) / len(remaining)

def merge_alternating(left, right):
    result = []
    max_length = max(len(left), len(right))
    for index in range(max_length):
        if index < len(left):
            result.append(left[index])
        if index < len(right):
            result.append(right[index])
    return result

def unique_in_order(items):
    seen = set()
    result = []
    for item in items:
        if item not in seen:
            seen.add(item)
            result.append(item)
    return result

def word_counts(text):
    counts = {}
    for word in text.lower().split():
        counts[word] = counts.get(word, 0) + 1
    return counts

def inventory_value(inventory, prices):
    total = 0
    for item, quantity in inventory.items():
        if item in prices:
            total += quantity * prices[item]
    return total

def invert_dictionary(mapping):
    inverted = {}
    for key, value in mapping.items():
        inverted.setdefault(value, []).append(key)
    return inverted

def most_frequent_word(text):
    words = text.lower().split()
    if not words:
        return None
    counts = {}
    best_word = None
    best_count = 0
    for word in words:
        counts[word] = counts.get(word, 0) + 1
        if counts[word] > best_count:
            best_word = word
            best_count = counts[word]
    return best_word

def student_average(students, name):
    for student in students:
        if student["name"] == name:
            scores = student["scores"]
            if not scores:
                return None
            return sum(scores) / len(scores)
    return None

def row_sums(matrix):
    result = []
    for row in matrix:
        result.append(sum(row))
    return result

def find_product(products, product_id):
    for product in products:
        if product["id"] == product_id:
            return product
    return None

def transpose(matrix):
    if not matrix:
        return []
    result = []
    for column_index in range(len(matrix[0])):
        new_row = []
        for row in matrix:
            new_row.append(row[column_index])
        result.append(new_row)
    return result

def average_by_course(records):
    totals = {}
    counts = {}
    for record in records:
        course = record["course"]
        totals[course] = totals.get(course, 0) + record["score"]
        counts[course] = counts.get(course, 0) + 1
    averages = {}
    for course in totals:
        averages[course] = totals[course] / counts[course]
    return averages

def factorial(n):
    if n == 0:
        return 1
    return n * factorial(n - 1)

def recursive_sum(numbers):
    if not numbers:
        return 0
    return numbers[0] + recursive_sum(numbers[1:])

def fibonacci(n):
    if n == 0:
        return 0
    if n == 1:
        return 1
    return fibonacci(n - 1) + fibonacci(n - 2)

def flatten(items):
    result = []
    for item in items:
        if isinstance(item, list):
            result.extend(flatten(item))
        else:
            result.append(item)
    return result

def power(base, exponent):
    if exponent == 0:
        return 1
    return base * power(base, exponent - 1)

class BankAccount:
    def __init__(self, owner, balance):
        self.owner = owner
        self.balance = balance

    def deposit(self, amount):
        self.balance += amount
        return self.balance

class Counter:
    def __init__(self):
        self.value = 0

    def increment(self):
        self.value += 1
        return self.value

    def reset(self):
        self.value = 0
        return self.value

class Book:
    def __init__(self, title, author, pages):
        self.title = title
        self.author = author
        self.pages = pages

    def description(self):
        return f"{self.title} by {self.author}, {self.pages} pages"

class Playlist:
    def __init__(self, name):
        self.name = name
        self.songs = []

    def add_song(self, title, seconds):
        self.songs.append({"title": title, "seconds": seconds})

    def total_duration(self):
        total = 0
        for song in self.songs:
            total += song["seconds"]
        return total

class StudentProgress:
    def __init__(self, student_name):
        self.student_name = student_name
        self.mastery = {}

    def update_mastery(self, kc_id, value):
        self.mastery[kc_id] = value

    def weakest_kc(self):
        if not self.mastery:
            return None
        return min(self.mastery, key=self.mastery.get)

def safe_divide(a, b):
    if b == 0:
        return None
    return a / b

def validate_age(age):
    if age < 0 or age > 120:
        raise ValueError("invalid age")
    return age

def parse_int_list(text):
    if text == "":
        return []
    result = []
    for part in text.split(","):
        try:
            result.append(int(part.strip()))
        except ValueError:
            return None
    return result

def require_non_empty(text):
    stripped = text.strip()
    if not stripped:
        raise ValueError("empty text")
    return stripped

def get_required(data, key):
    if key not in data:
        raise KeyError(key)
    return data[key]

def fizz_buzz(n):
    result = []
    for number in range(1, n + 1):
        if number % 15 == 0:
            result.append("FizzBuzz")
        elif number % 3 == 0:
            result.append("Fizz")
        elif number % 5 == 0:
            result.append("Buzz")
        else:
            result.append(number)
    return result

def two_sum_indices(numbers, target):
    seen = {}
    for index, number in enumerate(numbers):
        needed = target - number
        if needed in seen:
            return [seen[needed], index]
        if number not in seen:
            seen[number] = index
    return []

def binary_search(sorted_numbers, target):
    low = 0
    high = len(sorted_numbers) - 1
    while low <= high:
        middle = (low + high) // 2
        if sorted_numbers[middle] == target:
            return middle
        if sorted_numbers[middle] < target:
            low = middle + 1
        else:
            high = middle - 1
    return -1

def run_length_encode(text):
    if not text:
        return ""
    result = []
    current = text[0]
    count = 1
    for char in text[1:]:
        if char == current:
            count += 1
        else:
            result.append(current + str(count))
            current = char
            count = 1
    result.append(current + str(count))
    return "".join(result)

def recommend_exercise(mastery, exercises):
    if not exercises:
        return None
    best_exercise = None
    best_score = None
    for exercise in exercises:
        score = min(mastery.get(kc_id, 0) for kc_id in exercise["kc_tags"])
        if best_score is None or score < best_score:
            best_score = score
            best_exercise = exercise
    return best_exercise["id"]
